import { Component, h, Host } from '@stencil/core';
const N = 100;
const width = 450;
const height = 50;
const heights = Array(N).fill(height)
  .map(height => Math.floor(height * (1 + Math.random() * 2)));
const colors = [
  'red',
  'orange',
  'yellow',
  'green',
  'cyan',
  'blue',
  'purple',
];
export class VirtualScrollListDemo {
  renderItem(i) {
    let color = colors[i % colors.length];
    let height = heights[i];
    return h("div", { style: {
        width: width + 'px',
        height: height + 'px',
        outline: '1px solid ' + color,
        position: 'relative',
      } },
      h("div", { style: {
          position: 'absolute',
          top: '0',
          left: '0',
        } }, i),
      h("div", { style: {
          position: 'absolute',
          top: '0',
          right: '0',
        } }, i),
      h("div", { style: {
          position: 'absolute',
          bottom: '0',
          left: '0',
        } }, i),
      h("div", { style: {
          position: 'absolute',
          bottom: '0',
          right: '0',
        } }, i));
  }
  render() {
    return (h(Host, null,
      "before",
      h("virtual-scroll-list", { itemCount: N, renderItem: i => this.renderItem(i), itemWidth: width, itemHeights: heights, estimatedItemHeight: height, style: {
          display: 'block',
          width: '100%',
          height: '450px',
          maxHeight: '80vh',
          outline: 'blue solid 1px',
        } }),
      "after"));
  }
  static get is() { return "virtual-scroll-list-demo"; }
  static get encapsulation() { return "scoped"; }
  static get originalStyleUrls() { return {
    "$": ["virtual-scroll-list-demo.css"]
  }; }
  static get styleUrls() { return {
    "$": ["virtual-scroll-list-demo.css"]
  }; }
}
